setup:
# --- grid helper (hidden) — builds a truth table from YOUR gates ---
# For every input combination it calls the student's own AND / OR / XOR / NOT.
# A finished gate lights its square; an unfinished or wrong one shows '?'. The
# input columns (digits) and header always render, so the panel is never blank.
# Returns {grid, caption}: the caption is the readable legend (shown below).
def __cell(name, args, color):
    fn = globals().get(name)
    if fn is None:
        return "?"          # gate not written yet
    try:
        v = fn(*args)
    except Exception:
        return "?"          # gate crashed
    if v == 1:
        return color        # lights up
    if v == 0:
        return ""           # empty square
    return "?"              # not a clean 0/1

def __grid():
    rows = [["A", "B", "&", "|", "^", "!"]]
    for a, b in ([0, 0], [0, 1], [1, 0], [1, 1]):
        rows.append([
            str(a), str(b),
            __cell("AND", [a, b], "green"),
            __cell("OR", [a, b], "blue"),
            __cell("XOR", [a, b], "purple"),
            __cell("NOT", [a], "orange"),
        ])
    return {
        "grid": rows,
        "caption": "Columns are your gates: & = AND, | = OR, ^ = XOR, ! = NOT. A square lights up when that gate outputs 1. A ? means you haven't written that gate yet.",
    }
